steps.solution:
def tag_user(user, tag):
    new_user = {}
    new_user["name"] = user["name"]
    new_user["tags"] = user["tags"].copy()
    new_user["tags"].append(tag)
    return new_user

original = {"name": "maya", "tags": ["pm"]}
tagged = tag_user(original, "vip")

print(f"original tags: {original['tags']}")
print(f"tagged tags: {tagged['tags']}")

import copy

def clone_user(user):
    return copy.deepcopy(user)

alex = {"name": "alex", "roles": ["member"]}
cloned = clone_user(alex)
cloned["roles"].append("admin")

print(f"original roles: {alex['roles']}")
print(f"cloned roles: {cloned['roles']}")
